// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

/**
 * @title  InsuranceClaims
 * @notice Automates insurance claim lifecycle: Submitted → Approved → Paid
 *         or Submitted → Rejected.  Includes ETH-based demo payout.
 *
 * CHANGES FROM v1:
 *  - CRITICAL FIX: payClaim() now uses Checks-Effects-Interactions (CEI)
 *    pattern + nonReentrant guard — the classic reentrancy bug is closed
 *  - Claim cooldown: one claim per patient per 30 days (fraud prevention)
 *  - Duplicate / suspicious claim detection with ClaimFraudFlagged event
 *  - Interface updated to hasValidConsent()
 *  - diagnosisHash added to claim struct — links claim to diagnosis
 *  - payClaim() implemented (was missing in v1 — ClaimPaid event existed
 *    but no function to trigger it)
 *  - receive() payable added so the contract can accept ETH from the insurer
 *    for demo funding
 *  - withdraw() for insurer to recover unused demo ETH
 */

// ─── Interfaces ─────────────────────────────────────────────────────────────
interface IPatientConsent {
    function isRegisteredPatient(address patient) external view returns (bool);
    function hasValidConsent(address patient, address delegate) external view returns (bool);
}

interface IAccessControl {
    function hasRole(bytes32 role, address account) external view returns (bool);
    function INSURER_ROLE() external pure returns (bytes32);
}
// ────────────────────────────────────────────────────────────────────────────

abstract contract ReentrancyGuard {
    uint256 private _guardStatus = 1;
    modifier nonReentrant() {
        require(_guardStatus == 1, "ReentrancyGuard: reentrant call");
        _guardStatus = 2;
        _;
        _guardStatus = 1;
    }
}

contract InsuranceClaims is ReentrancyGuard {

    // ─────────────────────────────────────────────────────────────
    // Types
    // ─────────────────────────────────────────────────────────────
    enum ClaimStatus { Submitted, Approved, Rejected, Paid }

    struct Claim {
        uint256     claimId;
        address     patient;
        address     hospital;           // who submitted the claim
        uint256     amount;             // wei (demo value — not real money)
        ClaimStatus status;
        string      diagnosisHash;      // IPFS hash of diagnosis doc for verification
        uint256     submittedAt;
        uint256     resolvedAt;         // timestamp of approval/rejection/payment
    }

    // ─────────────────────────────────────────────────────────────
    // State
    // ─────────────────────────────────────────────────────────────
    IPatientConsent public identityContract;
    IAccessControl  public accessControl;

    uint256 public claimCount;
    mapping(uint256 => Claim)    public claims;

    // patient => last claim submission timestamp (for cooldown)
    mapping(address => uint256)  public lastClaimTime;

    // patient => number of claims in the last 30-day window (fraud check)
    mapping(address => uint256)  public claimsInWindow;

    // Fraud thresholds
    uint256 public constant CLAIM_COOLDOWN    = 30 days;
    uint256 public constant MAX_CLAIMS_WINDOW = 3;          // max 3 claims per 30-day window

    // ─────────────────────────────────────────────────────────────
    // Events
    // ─────────────────────────────────────────────────────────────
    event ClaimSubmitted(
        uint256 indexed claimId,
        address indexed patient,
        address indexed hospital,
        uint256 amount,
        string  diagnosisHash,
        uint256 timestamp
    );
    event ClaimApproved(uint256 indexed claimId, address indexed approvedBy, uint256 timestamp);
    event ClaimRejected(uint256 indexed claimId, address indexed rejectedBy, string reason, uint256 timestamp);
    event ClaimPaid(uint256 indexed claimId, address indexed patient, uint256 amount, uint256 timestamp);
    event ClaimFraudFlagged(
        uint256 indexed claimId,
        address indexed patient,
        string  reason,
        uint256 timestamp
    );

    // ─────────────────────────────────────────────────────────────
    // Modifiers
    // ─────────────────────────────────────────────────────────────
    modifier onlyInsurer() {
        require(
            accessControl.hasRole(accessControl.INSURER_ROLE(), msg.sender),
            "Only registered insurer allowed"
        );
        _;
    }
    modifier onlyRegisteredPatient(address patient) {
        require(identityContract.isRegisteredPatient(patient), "Patient not registered");
        _;
    }
    modifier hasConsent(address patient) {
        require(identityContract.hasValidConsent(patient, msg.sender), "No valid consent from patient");
        _;
    }

    // ─────────────────────────────────────────────────────────────
    // Constructor
    // ─────────────────────────────────────────────────────────────
    constructor(address _identityContract, address _accessControl) {
        require(_identityContract != address(0), "Invalid identity contract");
        require(_accessControl    != address(0), "Invalid access control contract");
        identityContract = IPatientConsent(_identityContract);
        accessControl    = IAccessControl(_accessControl);
    }

    // ─────────────────────────────────────────────────────────────
    // Receive ETH — insurer funds the contract for demo payouts
    // ─────────────────────────────────────────────────────────────
    receive() external payable {}

    // ─────────────────────────────────────────────────────────────
    // Hospital / clinic functions
    // ─────────────────────────────────────────────────────────────

    /**
     * @notice Submit a new insurance claim on behalf of a patient.
     *         Fraud checks: cooldown period + rolling window limit.
     * @param  patient        Patient's address
     * @param  amount         Claim amount in wei (demo only)
     * @param  diagnosisHash  IPFS CID of the supporting diagnosis document
     */
    function submitClaim(
        address patient,
        uint256 amount,
        string  memory diagnosisHash
    )
        external
        onlyRegisteredPatient(patient)
        hasConsent(patient)
        nonReentrant
    {
        require(amount > 0, "Claim amount must be positive");
        require(bytes(diagnosisHash).length > 0, "Diagnosis hash required");

        // ── Fraud check 1: cooldown ──────────────────────────────
        if (lastClaimTime[patient] != 0) {
            uint256 elapsed = block.timestamp - lastClaimTime[patient];
            if (elapsed >= CLAIM_COOLDOWN) {
                // Window has reset — reset counter
                claimsInWindow[patient] = 0;
            }
        }

        // ── Fraud check 2: rolling window claim count ────────────
        if (claimsInWindow[patient] >= MAX_CLAIMS_WINDOW) {
            claimCount++;
            // Record it but immediately flag as suspicious
            claims[claimCount] = Claim({
                claimId:       claimCount,
                patient:       patient,
                hospital:      msg.sender,
                amount:        amount,
                status:        ClaimStatus.Rejected,
                diagnosisHash: diagnosisHash,
                submittedAt:   block.timestamp,
                resolvedAt:    block.timestamp
            });
            emit ClaimFraudFlagged(
                claimCount, patient,
                "Exceeded maximum claims per 30-day window",
                block.timestamp
            );
            return;
        }

        // ── All checks passed — create claim ─────────────────────
        claimCount++;
        claims[claimCount] = Claim({
            claimId:       claimCount,
            patient:       patient,
            hospital:      msg.sender,
            amount:        amount,
            status:        ClaimStatus.Submitted,
            diagnosisHash: diagnosisHash,
            submittedAt:   block.timestamp,
            resolvedAt:    0
        });

        lastClaimTime[patient] = block.timestamp;
        claimsInWindow[patient]++;

        emit ClaimSubmitted(claimCount, patient, msg.sender, amount, diagnosisHash, block.timestamp);
    }

    // ─────────────────────────────────────────────────────────────
    // Insurer functions
    // ─────────────────────────────────────────────────────────────

    /**
     * @notice Approve a submitted claim (insurer only).
     */
    function approveClaim(uint256 claimId) external onlyInsurer nonReentrant {
        Claim storage c = claims[claimId];
        require(c.claimId != 0,                          "Claim does not exist");
        require(c.status == ClaimStatus.Submitted,       "Claim not in Submitted state");

        c.status     = ClaimStatus.Approved;
        c.resolvedAt = block.timestamp;

        emit ClaimApproved(claimId, msg.sender, block.timestamp);
    }

    /**
     * @notice Reject a submitted claim (insurer only).
     * @param  reason  Human-readable rejection reason (stored in event log)
     */
    function rejectClaim(uint256 claimId, string memory reason)
        external
        onlyInsurer
        nonReentrant
    {
        Claim storage c = claims[claimId];
        require(c.claimId != 0,                    "Claim does not exist");
        require(c.status == ClaimStatus.Submitted, "Claim not in Submitted state");

        c.status     = ClaimStatus.Rejected;
        c.resolvedAt = block.timestamp;

        emit ClaimRejected(claimId, msg.sender, reason, block.timestamp);
    }

    /**
     * @notice Pay out an approved claim to the patient.
     *
     * SECURITY — Checks-Effects-Interactions pattern:
     *   1. CHECK:  verify state is Approved and contract has sufficient balance
     *   2. EFFECT: update state BEFORE transferring ETH
     *   3. INTERACT: transfer ETH last
     *   + nonReentrant guard as a second line of defence
     */
    function payClaim(uint256 claimId) external onlyInsurer nonReentrant {
        Claim storage c = claims[claimId];

        // ── 1. CHECKS ─────────────────────────────────────────────
        require(c.claimId != 0,                    "Claim does not exist");
        require(c.status == ClaimStatus.Approved,  "Claim must be Approved before payment");
        require(address(this).balance >= c.amount, "Insufficient contract balance for payout");

        // ── 2. EFFECTS (update state before any external call) ────
        address payable recipient = payable(c.patient);
        uint256 payoutAmount      = c.amount;
        c.status     = ClaimStatus.Paid;
        c.resolvedAt = block.timestamp;

        emit ClaimPaid(claimId, recipient, payoutAmount, block.timestamp);

        // ── 3. INTERACTION (ETH transfer last) ────────────────────
        (bool success, ) = recipient.call{value: payoutAmount}("");
        require(success, "ETH transfer to patient failed");
    }

    /**
     * @notice Withdraw remaining ETH from the contract (insurer only).
     *         Used at end of demo to recover unused test ETH.
     */
    function withdraw() external onlyInsurer nonReentrant {
        uint256 balance = address(this).balance;
        require(balance > 0, "Nothing to withdraw");
        (bool success, ) = payable(msg.sender).call{value: balance}("");
        require(success, "Withdrawal failed");
    }

    // ─────────────────────────────────────────────────────────────
    // View functions
    // ─────────────────────────────────────────────────────────────

    /// @notice Returns contract ETH balance (useful for demo dashboard)
    function getContractBalance() external view returns (uint256) {
        return address(this).balance;
    }

    /// @notice Returns claim details
    function getClaim(uint256 claimId) external view returns (Claim memory) {
        require(claims[claimId].claimId != 0, "Claim does not exist");
        return claims[claimId];
    }
}

contracts/PrescriptionAndDiagnosis.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

/**
 * @title  PrescriptionAndDiagnosis
 * @notice Doctors write diagnoses and prescriptions on-chain (IPFS hash +
 *         metadata).  Prescriptions have an expiry and a lifecycle:
 *         ISSUED → DISPENSED | EXPIRED.
 *
 * CHANGES FROM v1:
 *  - PrescriptionStatus enum: ISSUED, DISPENSED, EXPIRED
 *  - Prescriptions carry an expiresAt timestamp (default 180 days / 6 months)
 *  - dispensePrescription() added — only pharmacists can call it
 *  - expirePrescription() can be called by anyone after expiresAt
 *  - getPrescription() getter added — DrugAuthenticity.sol calls this
 *  - isValidPrescription() pure view — returns bool for cross-contract use
 *  - Interface updated to hasValidConsent()
 *  - ReentrancyGuard on all state-changing functions
 *  - Role checks via HealthcareAccessControl interface
 */

// ─── Interfaces ─────────────────────────────────────────────────────────────
interface IPatientConsent {
    function isRegisteredPatient(address patient) external view returns (bool);
    function hasValidConsent(address patient, address delegate) external view returns (bool);
}

interface IAccessControl {
    function hasRole(bytes32 role, address account) external view returns (bool);
    function PHARMACIST_ROLE() external pure returns (bytes32);
    function DOCTOR_ROLE()     external pure returns (bytes32);
}
// ────────────────────────────────────────────────────────────────────────────

abstract contract ReentrancyGuard {
    uint256 private _guardStatus = 1;
    modifier nonReentrant() {require(_guardStatus == 1, "ReentrancyGuard: reentrant call");
        _guardStatus = 2;
        _;
        _guardStatus = 1;
    }
}

contract PrescriptionAndDiagnosis is ReentrancyGuard {

    // ─────────────────────────────────────────────────────────────
    // Types
    // ─────────────────────────────────────────────────────────────

    enum PrescriptionStatus { ISSUED, DISPENSED, EXPIRED }

    struct Diagnosis {
        uint256 diagnosisId;
        address patient;
        address doctor;
        string  diagnosisDetails;   // e.g. "Type-2 Diabetes, Hypertension"
        string  ipfsHash;           // IPFS CID of detailed diagnosis doc (optional)
        uint256 timestamp;
    }

    struct Prescription {
        uint256 prescriptionId;
        address patient;
        address doctor;
        string  medicationDetails;  // e.g. "Metformin 500mg twice daily"
        string  ipfsHash;           // IPFS CID of prescription doc
        PrescriptionStatus status;
        uint256 issuedAt;
        uint256 expiresAt;          // prescription is invalid after this
        address dispensedBy;        // pharmacist who dispensed (0 if not yet)
        uint256 dispensedAt;
    }

    // ─────────────────────────────────────────────────────────────
    // State
    // ─────────────────────────────────────────────────────────────
    IPatientConsent public identityContract;
    IAccessControl  public accessControl;

    uint256 public diagnosisCount;
    uint256 public prescriptionCount;

    mapping(uint256 => Diagnosis)    public diagnoses;
    mapping(uint256 => Prescription) public prescriptions;

    // patient => list of their prescription IDs
    mapping(address => uint256[]) private _patientPrescriptions;
    // patient => list of their diagnosis IDs
    mapping(address => uint256[]) private _patientDiagnoses;

    // Default prescription validity: 180 days (6 months)
    uint256 public constant DEFAULT_PRESCRIPTION_VALIDITY = 180 days;

    // ─────────────────────────────────────────────────────────────
    // Events
    // ─────────────────────────────────────────────────────────────
    event DiagnosisAdded(
        uint256 indexed diagnosisId,
        address indexed patient,
        address indexed doctor,
        uint256 timestamp
    );
    event PrescriptionAdded(
        uint256 indexed prescriptionId,
        address indexed patient,
        address indexed doctor,
        uint256 expiresAt
    );
    event PrescriptionDispensed(
        uint256 indexed prescriptionId,
        address indexed patient,
        address indexed pharmacist,
        uint256 dispensedAt
    );
    event PrescriptionExpired(
        uint256 indexed prescriptionId,
        address indexed patient,
        uint256 expiredAt
    );

    // ─────────────────────────────────────────────────────────────
    // Modifiers
    // ─────────────────────────────────────────────────────────────
    modifier onlyRegisteredPatient(address patient) {
        require(identityContract.isRegisteredPatient(patient), "Patient not registered");
        _;
    }
    modifier hasConsent(address patient) {
        require(identityContract.hasValidConsent(patient, msg.sender), "No valid consent from patient");
        _;
    }
    modifier onlyPharmacist() {
        require(
            accessControl.hasRole(accessControl.PHARMACIST_ROLE(), msg.sender),
            "Only a registered pharmacist can dispense"
        );
        _;
    }

    // ─────────────────────────────────────────────────────────────
    // Constructor
    // ─────────────────────────────────────────────────────────────
    constructor(address _identityContract, address _accessControl) {
        require(_identityContract != address(0), "Invalid identity contract");
        require(_accessControl    != address(0), "Invalid access control contract");
        identityContract = IPatientConsent(_identityContract);
        accessControl    = IAccessControl(_accessControl);
    }

    // ─────────────────────────────────────────────────────────────
    // Doctor functions
    // ─────────────────────────────────────────────────────────────

    /**
     * @notice Add a diagnosis for a patient.
     *         Caller must be a consented doctor.
     */
    function addDiagnosis(
        address patient,
        string  memory diagnosisDetails,
        string  memory ipfsHash
    )
        external
        onlyRegisteredPatient(patient)
        hasConsent(patient)
        nonReentrant
    {
        require(bytes(diagnosisDetails).length > 0, "Diagnosis details required");

        diagnosisCount++;
        diagnoses[diagnosisCount] = Diagnosis({
            diagnosisId:      diagnosisCount,
            patient:          patient,
            doctor:           msg.sender,
            diagnosisDetails: diagnosisDetails,
            ipfsHash:         ipfsHash,
            timestamp:        block.timestamp
        });

        _patientDiagnoses[patient].push(diagnosisCount);
        emit DiagnosisAdded(diagnosisCount, patient, msg.sender, block.timestamp);
    }

    /**
     * @notice Add a prescription for a patient.
     * @param  validityDays  0 = use default 180 days
     */
    function addPrescription(
        address patient,
        string  memory medicationDetails,
        string  memory ipfsHash,
        uint256 validityDays
    )
        external
        onlyRegisteredPatient(patient)
        hasConsent(patient)
        nonReentrant
    {
        require(bytes(medicationDetails).length > 0, "Medication details required");

        uint256 validity  = validityDays == 0 ? DEFAULT_PRESCRIPTION_VALIDITY : validityDays * 1 days;
        uint256 expiresAt = block.timestamp + validity;

        prescriptionCount++;
        prescriptions[prescriptionCount] = Prescription({
            prescriptionId:    prescriptionCount,
            patient:           patient,
            doctor:            msg.sender,
            medicationDetails: medicationDetails,
            ipfsHash:          ipfsHash,
            status:            PrescriptionStatus.ISSUED,
            issuedAt:          block.timestamp,
            expiresAt:         expiresAt,
            dispensedBy:       address(0),
            dispensedAt:       0
        });

        _patientPrescriptions[patient].push(prescriptionCount);
        emit PrescriptionAdded(prescriptionCount, patient, msg.sender, expiresAt);
    }

    // ─────────────────────────────────────────────────────────────
    // Pharmacist functions
    // ─────────────────────────────────────────────────────────────

    /**
     * @notice Mark a prescription as dispensed.
     *         Only callable by a registered pharmacist.
     *         Validates the prescription is still ISSUED and not expired.
     *         DrugAuthenticity.sol calls isValidPrescription() before this.
     */
    function dispensePrescription(uint256 prescriptionId)
        external
        onlyPharmacist
        nonReentrant
    {
        Prescription storage p = prescriptions[prescriptionId];
        require(p.prescriptionId != 0,                      "Prescription does not exist");
        require(p.status == PrescriptionStatus.ISSUED,       "Prescription already dispensed or expired");
        require(block.timestamp < p.expiresAt,               "Prescription has expired");

        p.status      = PrescriptionStatus.DISPENSED;
        p.dispensedBy = msg.sender;
        p.dispensedAt = block.timestamp;

        emit PrescriptionDispensed(prescriptionId, p.patient, msg.sender, block.timestamp);
    }

    /**
     * @notice Mark a prescription as EXPIRED.
     *         Anyone can call this on an overdue prescription (used by bots / cron).
     */
    function expirePrescription(uint256 prescriptionId) external {
        Prescription storage p = prescriptions[prescriptionId];
        require(p.prescriptionId != 0,                      "Prescription does not exist");
        require(p.status == PrescriptionStatus.ISSUED,       "Not in ISSUED state");
        require(block.timestamp >= p.expiresAt,              "Prescription has not expired yet");

        p.status = PrescriptionStatus.EXPIRED;
        emit PrescriptionExpired(prescriptionId, p.patient, block.timestamp);
    }

    // ─────────────────────────────────────────────────────────────
    // View functions
    // ─────────────────────────────────────────────────────────────

    /**
     * @notice Primary cross-contract check used by DrugAuthenticity.
     *         Returns true only if prescription is ISSUED and not expired.
     */
    function isValidPrescription(uint256 prescriptionId)
        external
        view
        returns (bool)
    {
        Prescription memory p = prescriptions[prescriptionId];
        return (
            p.prescriptionId != 0 &&
            p.status == PrescriptionStatus.ISSUED &&
            block.timestamp < p.expiresAt
        );
    }

    /**
     * @notice Returns full prescription struct — called by DrugAuthenticity
     *         to get the patient address for validation.
     */
    function getPrescription(uint256 prescriptionId)
        external
        view
        returns (Prescription memory)
    {
        require(prescriptions[prescriptionId].prescriptionId != 0, "Prescription does not exist");
        return prescriptions[prescriptionId];
    }

    /// @notice Returns all prescription IDs for a patient
    function getPrescriptionsByPatient(address patient) external view returns (uint256[] memory) {
        return _patientPrescriptions[patient];
    }

    /// @notice Returns all diagnosis IDs for a patient
    function getDiagnosesByPatient(address patient) external view returns (uint256[] memory) {
        return _patientDiagnoses[patient];
    }
}

contracts/HealthCareAccessControl.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

/**
 * @title  HealthcareAccessControl
 * @notice Central Role-Based Access Control for the SC-BHIoT system.
 *         Deploy this CONTRACT FIRST and pass its address to every other
 *         contract's constructor.
 *
 * @dev    Roles are defined as keccak256 hashes so they're cheap to store
 *         and compare on-chain.  The systemAdmin can grant / revoke any role.
 */
contract HealthcareAccessControl {

    // ─────────────────────────────────────────────────────────────
    // Role constants  (keccak256 of a human-readable label)
    // ─────────────────────────────────────────────────────────────
    bytes32 public constant DOCTOR_ROLE       = keccak256("DOCTOR_ROLE");
    bytes32 public constant PHARMACIST_ROLE   = keccak256("PHARMACIST_ROLE");
    bytes32 public constant INSURER_ROLE      = keccak256("INSURER_ROLE");
    bytes32 public constant RESEARCHER_ROLE   = keccak256("RESEARCHER_ROLE");
    bytes32 public constant MANUFACTURER_ROLE = keccak256("MANUFACTURER_ROLE");
    bytes32 public constant DISTRIBUTOR_ROLE  = keccak256("DISTRIBUTOR_ROLE");
    bytes32 public constant REGULATOR_ROLE    = keccak256("REGULATOR_ROLE");
    bytes32 public constant HOSPITAL_ROLE     = keccak256("HOSPITAL_ROLE");
    bytes32 public constant IOT_DEVICE_ROLE   = keccak256("IOT_DEVICE_ROLE");

    // ─────────────────────────────────────────────────────────────
    // State
    // ─────────────────────────────────────────────────────────────
    address public systemAdmin;
    // role => account => granted
    mapping(bytes32 => mapping(address => bool)) private _roles;

    // ─────────────────────────────────────────────────────────────
    // Events
    // ─────────────────────────────────────────────────────────────
    event RoleGranted(bytes32 indexed role, address indexed account, address indexed grantedBy);
    event RoleRevoked(bytes32 indexed role, address indexed account, address indexed revokedBy);
    event AdminTransferred(address indexed oldAdmin, address indexed newAdmin);

    // ─────────────────────────────────────────────────────────────
    // Modifiers
    // ─────────────────────────────────────────────────────────────
    modifier onlyAdmin() {
        require(msg.sender == systemAdmin, "AccessControl: caller is not admin");
        _;
    }

    // ─────────────────────────────────────────────────────────────
    // Constructor
    // ─────────────────────────────────────────────────────────────
    constructor(address _admin) {
        require(_admin != address(0), "Invalid admin address");
        systemAdmin = _admin;
    }

    // ─────────────────────────────────────────────────────────────
    // Admin functions
    // ─────────────────────────────────────────────────────────────

    /// @notice Grant a role to an account (admin only)
    function grantRole(bytes32 role, address account) external onlyAdmin {
        require(account != address(0), "Invalid account address");
        require(!_roles[role][account], "Role already granted");
        _roles[role][account] = true;
        emit RoleGranted(role, account, msg.sender);
    }

    /// @notice Revoke a role from an account (admin only)
    function revokeRole(bytes32 role, address account) external onlyAdmin {
        require(_roles[role][account], "Role not currently assigned");
        _roles[role][account] = false;
        emit RoleRevoked(role, account, msg.sender);
    }

    /// @notice Transfer system admin to a new address
    function transferAdmin(address newAdmin) external onlyAdmin {
        require(newAdmin != address(0), "Invalid address");
        emit AdminTransferred(systemAdmin, newAdmin);
        systemAdmin = newAdmin;
    }

    // ─────────────────────────────────────────────────────────────
    // View functions
    // ─────────────────────────────────────────────────────────────

    /// @notice Check if an account holds a specific role
    function hasRole(bytes32 role, address account) external view returns (bool) {
        return _roles[role][account];
    }

    /// @notice Returns the role label for DOCTOR (helper for frontend)
    function getDoctorRole()      external pure returns (bytes32) { return DOCTOR_ROLE; }
    function getPharmacistRole()  external pure returns (bytes32) { return PHARMACIST_ROLE; }
    function getInsurerRole()     external pure returns (bytes32) { return INSURER_ROLE; }
    function getManufacturerRole()external pure returns (bytes32) { return MANUFACTURER_ROLE; }
    function getDistributorRole() external pure returns (bytes32) { return DISTRIBUTOR_ROLE; }
    function getRegulatorRole()   external pure returns (bytes32) { return REGULATOR_ROLE; }
    function getIoTDeviceRole()   external pure returns (bytes32) { return IOT_DEVICE_ROLE; }
}

contracts/IoTdatalogger.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

/**
 * @title  IoTDataLogger
 * @notice Anchors batched H-IoT device readings on-chain as IPFS hashes and
 *         emits on-chain alerts when vital sign thresholds are crossed.
 *
 * This contract is the blockchain anchor for the H-IoT layer described in
 * the SC-BHIoT paper.  Raw vitals are NEVER stored on-chain; only the IPFS
 * CID of an encrypted vitals batch is stored.  Threshold events are fully
 * on-chain so the frontend can subscribe and show live alerts.
 *
 * NEW CONTRACT — does not exist in v1.
 *
 * Architecture:
 *  IoT Device (Python sim) → MQTT broker → Node.js backend
 *    → encrypt + upload to IPFS → get CID
 *    → call logVitalsBatch() on this contract
 *    → smart contract checks thresholds and emits AlertTriggered if needed
 *    → frontend WebSocket receives the event and shows the alert dashboard
 */

// ─── Interface ───────────────────────────────────────────────────────────────
interface IAccessControl {
    function hasRole(bytes32 role, address account) external view returns (bool);
    function IOT_DEVICE_ROLE() external pure returns (bytes32);
    function REGULATOR_ROLE()  external pure returns (bytes32);
}
// ─────────────────────────────────────────────────────────────────────────────

abstract contract ReentrancyGuard {
    uint256 private _guardStatus = 1;
    modifier nonReentrant() {
        require(_guardStatus == 1, "ReentrancyGuard: reentrant call");
        _guardStatus = 2;
        _;
        _guardStatus = 1;
    }
}

contract IoTDataLogger is ReentrancyGuard {

    // ─────────────────────────────────────────────────────────────
    // Vital sign threshold constants
    // These match the H-IoT alert thresholds from the paper.
    // ─────────────────────────────────────────────────────────────
    uint256 public constant HR_HIGH    = 100;   // bpm  — tachycardia
    uint256 public constant HR_LOW     = 50;    // bpm  — bradycardia
    uint256 public constant SPO2_LOW   = 94;    // %    — hypoxia
    uint256 public constant BP_SYS_HIGH = 140;  // mmHg — hypertension
    uint256 public constant BP_DIA_HIGH = 90;   // mmHg — hypertension
    uint256 public constant GLUCOSE_HIGH = 180; // mg/dL — hyperglycaemia (post-meal)
    uint256 public constant GLUCOSE_LOW  = 70;  // mg/dL — hypoglycaemia

    // ─────────────────────────────────────────────────────────────
    // Types
    // ─────────────────────────────────────────────────────────────

    struct VitalsLog {
        uint256 logId;
        address device;         // IoT device address
        address patient;        // patient being monitored
        string  ipfsHash;       // IPFS CID of encrypted vitals batch
        uint256 timestamp;
    }

    struct AlertRecord {
        uint256 alertId;
        address patient;
        string  alertType;      // "HR_HIGH" | "SPO2_LOW" | "BP_HIGH" | etc.
        uint256 value;          // the threshold-crossing value
        uint256 threshold;      // the threshold that was crossed
        string  severity;       // "WARNING" | "CRITICAL"
        uint256 timestamp;
    }

    // ─────────────────────────────────────────────────────────────
    // State
    // ─────────────────────────────────────────────────────────────
    IAccessControl public accessControl;

    uint256 public logCount;
    uint256 public alertCount;

    mapping(uint256 => VitalsLog)   public vitalsLogs;
    mapping(uint256 => AlertRecord) public alertRecords;

    // patient => list of their log IDs
    mapping(address => uint256[]) private _patientLogs;
    // patient => list of their alert IDs
    mapping(address => uint256[]) private _patientAlerts;

    // device address => bool (whitelist)
    mapping(address => bool) public isRegisteredDevice;
    // device address => associated patient
    mapping(address => address) public devicePatient;

    // ─────────────────────────────────────────────────────────────
    // Events
    // ─────────────────────────────────────────────────────────────
    event DeviceRegistered(
        address indexed device,
        address indexed patient,
        uint256 timestamp
    );
    event DeviceDeregistered(
        address indexed device,
        uint256 timestamp
    );
    event VitalsLogged(
        uint256 indexed logId,
        address indexed device,
        address indexed patient,
        string  ipfsHash,
        uint256 timestamp
    );
    event AlertTriggered(
        uint256 indexed alertId,
        address indexed patient,
        string  alertType,
        uint256 value,
        uint256 threshold,
        string  severity,
        uint256 timestamp
    );

    // ─────────────────────────────────────────────────────────────
    // Modifiers
    // ─────────────────────────────────────────────────────────────
    modifier onlyRegisteredDevice() {
        require(isRegisteredDevice[msg.sender], "Device not registered");
        _;
    }
    modifier onlyAdmin() {
        require(
            accessControl.hasRole(accessControl.REGULATOR_ROLE(), msg.sender),
            "Only admin/regulator can manage devices"
        );
        _;
    }

    // ─────────────────────────────────────────────────────────────
    // Constructor
    // ─────────────────────────────────────────────────────────────
    constructor(address _accessControl) {
        require(_accessControl != address(0), "Invalid access control address");
        accessControl = IAccessControl(_accessControl);
    }

    // ─────────────────────────────────────────────────────────────
    // Device management (admin only)
    // ─────────────────────────────────────────────────────────────

    /**
     * @notice Register a new IoT device and associate it with a patient.
     *         The device address is the wallet used by the backend IoT bridge.
     */
    function registerDevice(address device, address patient) external onlyAdmin nonReentrant {
        require(device  != address(0), "Invalid device address");
        require(patient != address(0), "Invalid patient address");
        require(!isRegisteredDevice[device], "Device already registered");

        isRegisteredDevice[device] = true;
        devicePatient[device]      = patient;

        emit DeviceRegistered(device, patient, block.timestamp);
    }

    /// @notice Remove a device from the whitelist (lost / replaced / retired)
    function deregisterDevice(address device) external onlyAdmin nonReentrant {
        require(isRegisteredDevice[device], "Device not registered");
        isRegisteredDevice[device] = false;
        emit DeviceDeregistered(device, block.timestamp);
    }

    // ─────────────────────────────────────────────────────────────
    // Vitals logging (called by the Node.js backend after IPFS upload)
    // ─────────────────────────────────────────────────────────────

    /**
     * @notice Log a batch of vitals readings anchored by their IPFS hash.
     *         Called by the Node.js IoT ingestion service after encrypting
     *         and uploading the readings to IPFS.
     * @param  ipfsHash   IPFS CID of the encrypted vitals JSON batch
     */
    function logVitalsBatch(string memory ipfsHash)
        external
        onlyRegisteredDevice
        nonReentrant
    {
        require(bytes(ipfsHash).length > 0, "IPFS hash required");

        address patient = devicePatient[msg.sender];
        logCount++;

        vitalsLogs[logCount] = VitalsLog({
            logId:     logCount,
            device:    msg.sender,
            patient:   patient,
            ipfsHash:  ipfsHash,
            timestamp: block.timestamp
        });

        _patientLogs[patient].push(logCount);
        emit VitalsLogged(logCount, msg.sender, patient, ipfsHash, block.timestamp);
    }

    /**
     * @notice Trigger a threshold alert.
     *         Called by the Node.js backend when it detects a threshold
     *         crossing in the raw sensor data BEFORE uploading to IPFS.
     *         The alert is stored on-chain for an immutable audit record.
     *
     * @param  patient    Patient being monitored
     * @param  alertType  String label: "HR_HIGH", "HR_LOW", "SPO2_LOW", etc.
     * @param  value      The actual sensor reading that triggered the alert
     * @param  threshold  The threshold constant that was crossed
     * @param  severity   "WARNING" or "CRITICAL"
     */
    function triggerAlert(
        address patient,
        string  memory alertType,
        uint256 value,
        uint256 threshold,
        string  memory severity
    )
        external
        onlyRegisteredDevice
        nonReentrant
    {
        require(patient    != address(0),   "Invalid patient address");
        require(bytes(alertType).length > 0, "Alert type required");
        require(bytes(severity).length  > 0, "Severity required");
        require(
            devicePatient[msg.sender] == patient,
            "Device not associated with this patient"
        );

        alertCount++;
        alertRecords[alertCount] = AlertRecord({
            alertId:   alertCount,
            patient:   patient,
            alertType: alertType,
            value:     value,
            threshold: threshold,
            severity:  severity,
            timestamp: block.timestamp
        });

        _patientAlerts[patient].push(alertCount);
        emit AlertTriggered(alertCount, patient, alertType, value, threshold, severity, block.timestamp);
    }

    // ─────────────────────────────────────────────────────────────
    // Convenience: backend can call this to check thresholds on-chain
    // instead of implementing logic client-side
    // ─────────────────────────────────────────────────────────────

    /**
     * @notice Returns whether a heart rate reading crosses any threshold.
     *         The backend can call this as a view before deciding to triggerAlert.
     */
    function checkHeartRate(uint256 bpm)
        external
        pure
        returns (bool exceeded, string memory alertType, string memory severity)
    {
        if (bpm > HR_HIGH)  return (true, "HR_HIGH", "WARNING");
        if (bpm < HR_LOW)   return (true, "HR_LOW",  "CRITICAL");
        return (false, "", "");
    }

    function checkSpO2(uint256 pct)
        external
        pure
        returns (bool exceeded, string memory alertType, string memory severity)
    {
        if (pct < SPO2_LOW) return (true, "SPO2_LOW", "CRITICAL");
        return (false, "", "");
    }

    function checkGlucose(uint256 mgdl)
        external
        pure
        returns (bool exceeded, string memory alertType, string memory severity)
    {
        if (mgdl > GLUCOSE_HIGH) return (true, "GLUCOSE_HIGH", "WARNING");
        if (mgdl < GLUCOSE_LOW)  return (true, "GLUCOSE_LOW",  "CRITICAL");
        return (false, "", "");
    }

    // ─────────────────────────────────────────────────────────────
    // View functions
    // ─────────────────────────────────────────────────────────────

    /// @notice Returns all vitals log IDs for a patient
    function getLogsByPatient(address patient) external view returns (uint256[] memory) {
        return _patientLogs[patient];
    }

    /// @notice Returns all alert IDs for a patient
    function getAlertsByPatient(address patient) external view returns (uint256[] memory) {
        return _patientAlerts[patient];
    }

    /// @notice Returns the latest log for a patient (most recent vitals)
    function getLatestLog(address patient) external view returns (VitalsLog memory) {
        uint256[] memory ids = _patientLogs[patient];
        require(ids.length > 0, "No vitals logged for this patient");
        return vitalsLogs[ids[ids.length - 1]];
    }

    /// @notice Returns threshold constants as a struct for frontend display
    function getThresholds() external pure returns (
        uint256 hrHigh, uint256 hrLow, uint256 spo2Low,
        uint256 bpSysHigh, uint256 glucoseHigh, uint256 glucoseLow
    ) {
        return (HR_HIGH, HR_LOW, SPO2_LOW, BP_SYS_HIGH, GLUCOSE_HIGH, GLUCOSE_LOW);
    }
}

contracts/MedicalRecordsAndAccess.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

/**
 * @title  MedicalRecordsAndAccess
 * @notice Stores encrypted medical record IPFS hashes on-chain and enforces
 *         patient-controlled, time-limited consent before allowing access.
 *
 * CHANGES FROM v1:
 *  - Interface updated to use hasValidConsent() — now checks expiry too
 *  - Record versioning: each patient has a version counter; updates append
 *    a new record rather than overwrite (immutable audit trail)
 *  - RecordAccessed event now includes the accessor's role string
 *  - getRecordsByPatient() added for frontend pagination
 *  - nonReentrant guard on all write functions
 *  - viewMedicalRecord split: returns hash + emits access log
 */

// ─── Interface for PatientIdentityAndConsent ────────────────────────────────
interface IPatientConsent {
    function isRegisteredPatient(address patient) external view returns (bool);
    function hasValidConsent(address patient, address delegate) external view returns (bool);
}
// ────────────────────────────────────────────────────────────────────────────

// ─── Inline ReentrancyGuard ──────────────────────────────────────────────────
abstract contract ReentrancyGuard {
    uint256 private _guardStatus = 1;
    modifier nonReentrant() {
        require(_guardStatus == 1, "ReentrancyGuard: reentrant call");
        _guardStatus = 2;
        _;
        _guardStatus = 1;
    }
}
// ────────────────────────────────────────────────────────────────────────────

contract MedicalRecordsAndAccess is ReentrancyGuard {

    // ─────────────────────────────────────────────────────────────
    // Types
    // ─────────────────────────────────────────────────────────────
    struct MedicalRecord {
        uint256 recordId;
        address patient;
        address uploadedBy;     // doctor or lab address
        string  ipfsHash;       // encrypted record CID on IPFS
        string  recordType;     // e.g. "LAB_REPORT", "XRAY", "DISCHARGE_SUMMARY"
        uint256 version;        // version number for this patient's record chain
        uint256 timestamp;
    }

    // ─────────────────────────────────────────────────────────────
    // State
    // ─────────────────────────────────────────────────────────────
    IPatientConsent public identityContract;

    uint256 public recordCount;

    // recordId => MedicalRecord
    mapping(uint256 => MedicalRecord) public medicalRecords;

    // patient => list of their recordIds  (for pagination)
    mapping(address => uint256[]) private _patientRecordIds;

    // patient => current version counter
    mapping(address => uint256) public patientRecordVersion;

    // ─────────────────────────────────────────────────────────────
    // Events
    // ─────────────────────────────────────────────────────────────
    event RecordAdded(
        uint256 indexed recordId,
        address indexed patient,
        address indexed uploadedBy,
        string  ipfsHash,
        string  recordType,
        uint256 version,
        uint256 timestamp
    );
    event RecordAccessed(
        uint256 indexed recordId,
        address indexed patient,
        address indexed accessedBy,
        string  accessorRole,   // "DOCTOR" | "INSURER" | "RESEARCHER" etc.
        uint256 timestamp
    );
    event RecordUpdated(uint256 indexed recordId, string oldHash, string newHash, uint256 timestamp);

    // ─────────────────────────────────────────────────────────────
    // Modifiers
    // ─────────────────────────────────────────────────────────────
    modifier onlyRegisteredPatient(address patient) {
        require(identityContract.isRegisteredPatient(patient), "Patient not registered");
        _;
    }
    modifier hasConsent(address patient) {
        require(identityContract.hasValidConsent(patient, msg.sender), "No valid consent from patient");
        _;
    }

    // ─────────────────────────────────────────────────────────────
    // Constructor
    // ─────────────────────────────────────────────────────────────
    constructor(address _identityContract) {
        require(_identityContract != address(0), "Invalid identity contract address");
        identityContract = IPatientConsent(_identityContract);
    }

    // ─────────────────────────────────────────────────────────────
    // Write functions
    // ─────────────────────────────────────────────────────────────

    /**
     * @notice Add a medical record for a patient.
     *         Caller must hold valid patient consent.
     * @param  patient     Patient's address
     * @param  ipfsHash    IPFS CID of the AES-256 encrypted record
     * @param  recordType  Human-readable type string ("LAB_REPORT", "PRESCRIPTION", etc.)
     */
    function addMedicalRecord(
        address patient,
        string  memory ipfsHash,
        string  memory recordType
    )
        external
        onlyRegisteredPatient(patient)
        hasConsent(patient)
        nonReentrant
    {
        require(bytes(ipfsHash).length   > 0, "IPFS hash required");
        require(bytes(recordType).length > 0, "Record type required");

        // Increment global record counter and patient version counter
        recordCount++;
        patientRecordVersion[patient]++;

        uint256 newVersion = patientRecordVersion[patient];

        medicalRecords[recordCount] = MedicalRecord({
            recordId:   recordCount,
            patient:    patient,
            uploadedBy: msg.sender,
            ipfsHash:   ipfsHash,
            recordType: recordType,
            version:    newVersion,
            timestamp:  block.timestamp
        });

        _patientRecordIds[patient].push(recordCount);

        emit RecordAdded(
            recordCount, patient, msg.sender,
            ipfsHash, recordType, newVersion, block.timestamp
        );
    }
    /**
     * @notice Allows the original doctor to correct a faulty record.
     * The old hash is permanently logged in the event history for auditing.
     */
    function updateMedicalRecord(uint256 _recordId, string memory _newIpfsHash) external {
        MedicalRecord storage rec = medicalRecords[_recordId];
        require(msg.sender == rec.uploadedBy, "Only the prescribing doctor can update this record");
        string memory oldHash = rec.ipfsHash;
        rec.ipfsHash = _newIpfsHash;
        emit RecordUpdated(_recordId, oldHash, _newIpfsHash, block.timestamp);
    }
    // ─────────────────────────────────────────────────────────────
    // Read functions
    // ─────────────────────────────────────────────────────────────

    /**
     * @notice View a specific medical record and emit an access log.
     *         Requires valid patient consent.
     * @param  recordId     The global record ID
     * @param  accessorRole Human-readable role label (passed by caller for the audit log)
     * @return ipfsHash     IPFS CID of the encrypted record
     */
    function viewMedicalRecord(uint256 recordId, string memory accessorRole)
        external
        returns (string memory ipfsHash)
    {
        require(recordId > 0 && recordId <= recordCount, "Invalid record ID");

        address patient = medicalRecords[recordId].patient;
        require(
            identityContract.hasValidConsent(patient, msg.sender),
            "No valid consent from patient"
        );

        emit RecordAccessed(recordId, patient, msg.sender, accessorRole, block.timestamp);
        return medicalRecords[recordId].ipfsHash;
    }

    /**
     * @notice Returns all record IDs belonging to a patient.
     *         Frontend uses this to paginate a patient's record history.
     * @param  patient  Patient's address
     */
    function getRecordsByPatient(address patient)
        external
        view
        returns (uint256[] memory)
    {
        return _patientRecordIds[patient];
    }

    /**
     * @notice Returns the total number of records for a patient.
     */
    function getRecordCount(address patient) external view returns (uint256) {
        return _patientRecordIds[patient].length;
    }
    /**
     * @notice Returns the latest version number of a patient's records.
     *         Useful for checking if a patient's records have been updated.
     */
    function getLatestVersion(address patient) external view returns (uint256) {
        return patientRecordVersion[patient];
    }

}

contracts/PatientIdentityAndConsent.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

/**
 * @title  PatientIdentityAndConsent
 * @notice Registers patients, manages metadata hashes (IPFS), and controls
 *         time-limited consent granted to doctors / hospitals / insurers.
 *
 * CHANGES FROM v1:
 *  - Consent now carries an expiresAt timestamp (GDPR-aligned, time-limited)
 *  - hasValidConsent() view replaces the raw `consents` bool mapping for
 *    cross-contract checks — all other contracts call this
 *  - ReentrancyGuard added to all state-changing functions
 *  - Event names standardised to PascalCase
 *  - Duplicate registration check was already there; strengthened guard
 *  - getConsentDetails() added so the frontend can display expiry
 */

// ─── Minimal inline ReentrancyGuard (no external dependency needed) ────────
abstract contract ReentrancyGuard {
    uint256 private _guardStatus = 1;
    modifier nonReentrant() {
        require(_guardStatus == 1, "ReentrancyGuard: reentrant call");
        _guardStatus = 2;
        _;
        _guardStatus = 1;
    }
}
// ────────────────────────────────────────────────────────────────────────────

contract PatientIdentityAndConsent is ReentrancyGuard {

    // ─────────────────────────────────────────────────────────────
    // Types
    // ─────────────────────────────────────────────────────────────

    /// @dev Replaces the old `mapping(address=>mapping(address=>bool))`
    ///      Consent is only valid when granted == true AND block.timestamp < expiresAt
    struct ConsentRecord {
        bool    granted;
        uint256 expiresAt;   // Unix timestamp; 0 = not granted
    }

    // ─────────────────────────────────────────────────────────────
    // State
    // ─────────────────────────────────────────────────────────────
    address public registryAdmin;
    address[] public registeredPatientsList;

    mapping(address => bool)   public isRegisteredPatient;
    mapping(address => string) public patientMetadata;      // address → IPFS hash

    // patient => delegate => ConsentRecord
    mapping(address => mapping(address => ConsentRecord)) private _consentRecords;

    // Default consent duration: 365 days (can be overridden per grant)
    uint256 public constant DEFAULT_CONSENT_DURATION = 365 days;

    // ─────────────────────────────────────────────────────────────
    // Events  (all PascalCase, all indexed for fast log filtering)
    // ─────────────────────────────────────────────────────────────
    event PatientRegistered(address indexed patient, address indexed registeredBy, string metadataHash, uint256 timestamp);
    event MetadataUpdated(address indexed patient, string newMetadataHash, uint256 timestamp);
    event ConsentGranted(address indexed patient, address indexed delegate, uint256 expiresAt);
    event ConsentRevoked(address indexed patient, address indexed delegate, uint256 revokedAt);

    // ─────────────────────────────────────────────────────────────
    // Modifiers
    // ─────────────────────────────────────────────────────────────
    modifier onlyRegistryAdmin() {
        require(msg.sender == registryAdmin, "Only RegistryAdmin can call this");
        _;
    }
    modifier onlyRegisteredPatient() {
        require(isRegisteredPatient[msg.sender], "Only a registered patient can call");
        _;
    }

    // ─────────────────────────────────────────────────────────────
    // Constructor
    // ─────────────────────────────────────────────────────────────
    constructor(address _registryAdmin) {
        require(_registryAdmin != address(0), "Invalid admin address");
        registryAdmin = _registryAdmin;
    }

    // ─────────────────────────────────────────────────────────────
    // Admin functions
    // ─────────────────────────────────────────────────────────────

    /**
     * @notice Register a new patient.  Only the registry admin calls this
     *         (e.g., hospital onboarding desk).
     * @param  patientAddress  Wallet address of the patient
     * @param  metadataHash    IPFS CID of encrypted patient profile JSON
     */
    function registerPatient(address patientAddress, string memory metadataHash)
        external
        onlyRegistryAdmin
        nonReentrant
    {
        require(patientAddress != address(0), "Invalid patient address");
        require(bytes(metadataHash).length > 0, "Metadata hash required");
        require(!isRegisteredPatient[patientAddress], "Patient already registered");

        isRegisteredPatient[patientAddress] = true;
        patientMetadata[patientAddress]     = metadataHash;
        registeredPatientsList.push(patientAddress);

        emit PatientRegistered(patientAddress, msg.sender, metadataHash, block.timestamp);
    }
    // function transferAdmin(address newAdmin) external onlyRegistryAdmin {
    //     require(newAdmin != address(0), "Cannot transfer to zero address");
    //     registryAdmin = newAdmin;
    // }

    // ─────────────────────────────────────────────────────────────
    // Patient functions
    // ─────────────────────────────────────────────────────────────

    /**
     * @notice Patient updates their own metadata IPFS hash.
     * @param  newMetadataHash  New IPFS CID
     */
    function updateMetadata(string memory newMetadataHash)
        external
        onlyRegisteredPatient
        nonReentrant
    {
        require(bytes(newMetadataHash).length > 0, "Hash cannot be empty");
        patientMetadata[msg.sender] = newMetadataHash;
        emit MetadataUpdated(msg.sender, newMetadataHash, block.timestamp);
    }

    /**
     * @notice Grant consent to a delegate (doctor / hospital / insurer) with
     *         a custom duration in days.  Pass 0 to use the default 365 days.
     * @param  delegate       Address to receive consent
     * @param  durationDays   How many days the consent is valid (0 = default)
     */
    function grantConsent(address delegate, uint256 durationDays)
        external
        onlyRegisteredPatient
        nonReentrant
    {
        require(delegate != address(0),    "Invalid delegate address");
        require(delegate != msg.sender,    "Cannot consent to yourself");

        uint256 duration  = durationDays == 0 ? DEFAULT_CONSENT_DURATION : durationDays * 1 days;
        uint256 expiresAt = block.timestamp + duration;

        _consentRecords[msg.sender][delegate] = ConsentRecord({ granted: true, expiresAt: expiresAt });
        emit ConsentGranted(msg.sender, delegate, expiresAt);
    }

    /**
     * @notice Revoke consent from a delegate immediately.
     * @param  delegate  Address whose consent is revoked
     */
    function revokeConsent(address delegate)
        external
        onlyRegisteredPatient
        nonReentrant
    {
        require(delegate != address(0), "Invalid delegate address");
        require(_consentRecords[msg.sender][delegate].granted, "No active consent to revoke");

        _consentRecords[msg.sender][delegate].granted   = false;
        _consentRecords[msg.sender][delegate].expiresAt = 0;
        emit ConsentRevoked(msg.sender, delegate, block.timestamp);
    }

    // ─────────────────────────────────────────────────────────────
    // View functions  (called by all other contracts)
    // ─────────────────────────────────────────────────────────────

    /**
     * @notice Primary cross-contract consent check.
     *         Returns true only if consent is granted AND not expired.
     * @param  patient   Patient's address
     * @param  delegate  Address requesting access (doctor, insurer, etc.)
     */

    function hasValidConsent(address patient, address delegate)
        external
        view
        returns (bool)
    {
        ConsentRecord memory r = _consentRecords[patient][delegate];
        return (r.granted && block.timestamp < r.expiresAt);
    }

    /**
     * @notice Returns the full consent details for a patient-delegate pair.
     *         Used by the frontend to show expiry date in the dashboard.
     */
    function getConsentDetails(address patient, address delegate)
        external
        view
        returns (bool granted, uint256 expiresAt, bool isExpired)
    {
        ConsentRecord memory r = _consentRecords[patient][delegate];
        granted   = r.granted;
        expiresAt = r.expiresAt;
        isExpired = (r.expiresAt > 0 && block.timestamp >= r.expiresAt);
    }
    // function getAllRegisteredPatients() external view returns (address[] memory) {
    //    return registeredPatientsList;
    //  }
}

contracts/DrugAuthenticity.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

/**
 * @title  DrugAuthenticity
 * @notice Tracks drug batches from manufacturer to patient with role-enforced
 *         stage transitions and cross-contract prescription validation at
 *         the point of sale.
 *
 * CHANGES FROM v1:
 *  - CRITICAL FIX: each stage transition now enforces the correct role
 *    (only DISTRIBUTOR can set InTransit, only PHARMACY can set AtPharmacy)
 *  - AtPharmacy stage was missing entirely — receiveAtPharmacy() added
 *  - markAsSold() now validates a valid prescription exists via
 *    IPrescriptionAndDiagnosis.isValidPrescription() AND calls
 *    dispensePrescription() to close the loop
 *  - flagCounterfeit() + CounterfeitFlagged event added
 *  - Full stage history array per batch (audit trail for the panel demo)
 *  - AccessControl interface replaces ad-hoc role mappings
 *  - ReentrancyGuard on all state-changing functions
 */

// ─── Interfaces ─────────────────────────────────────────────────────────────
interface IAccessControl {
    function hasRole(bytes32 role, address account) external view returns (bool);
    function MANUFACTURER_ROLE() external pure returns (bytes32);
    function DISTRIBUTOR_ROLE()  external pure returns (bytes32);
    function REGULATOR_ROLE()    external pure returns (bytes32);
    function PHARMACIST_ROLE()   external pure returns (bytes32);
}

interface IPrescriptionAndDiagnosis {
    function isValidPrescription(uint256 prescriptionId) external view returns (bool);
    function dispensePrescription(uint256 prescriptionId) external;
}
abstract contract ReentrancyGuard {
    uint256 private _guardStatus = 1;
    modifier nonReentrant() {require(_guardStatus == 1, "ReentrancyGuard: reentrant call");
        _guardStatus = 2;
        _;
        _guardStatus = 1;
    }
}
contract DrugAuthenticity is ReentrancyGuard {
    enum DrugStatus { Manufactured, InTransit, AtPharmacy, Sold, Flagged }

    struct DrugBatch {
        string      batchId;          // e.g. "IXPD007"
        string      drugName;         // e.g. "Prednisolone 5mg"
        address     manufacturer;
        address     currentOwner;
        DrugStatus  status;
        bool        isFlagged;        // counterfeit flag
        uint256     registeredAt;
        uint256     updatedAt;
    }

    struct StageEntry {
        DrugStatus  stage;
        address     actor;
        uint256     timestamp;
        string      note;             // optional note per stage
    }

    // ─────────────────────────────────────────────────────────────
    // State
    // ─────────────────────────────────────────────────────────────
    IAccessControl            public accessControl;
    IPrescriptionAndDiagnosis public prescriptionContract;

    // batchId => DrugBatch
    mapping(string => DrugBatch)     public drugBatches;

    // batchId => stage history (full audit trail)
    mapping(string => StageEntry[])  private _stageHistory;

    // ─────────────────────────────────────────────────────────────
    // Events
    // ─────────────────────────────────────────────────────────────
    event DrugRegistered(
        string  indexed batchId,
        string  drugName,
        address indexed manufacturer,
        uint256 timestamp
    );
    event DrugTransferredToDistributor(
        string  indexed batchId,
        address indexed from,
        address indexed to,
        uint256 timestamp
    );
    event DrugReceivedAtPharmacy(
        string  indexed batchId,
        address indexed pharmacy,
        uint256 timestamp
    );
    event DrugSold(
        string  indexed batchId,
        address indexed pharmacy,
        uint256 prescriptionId,
        uint256 timestamp
    );
    event CounterfeitFlagged(
        string  indexed batchId,
        address indexed reporter,
        string  reason,
        uint256 timestamp
    );

    // ─────────────────────────────────────────────────────────────
    // Modifiers
    // ─────────────────────────────────────────────────────────────
    modifier onlyManufacturer() {
        require(
            accessControl.hasRole(accessControl.MANUFACTURER_ROLE(), msg.sender),
            "Only manufacturer allowed"
        );
        _;
    }
    modifier onlyDistributor() {
        require(
            accessControl.hasRole(accessControl.DISTRIBUTOR_ROLE(), msg.sender),
            "Only distributor allowed"
        );
        _;
    }
    modifier onlyPharmacist() {
        require(
            accessControl.hasRole(accessControl.PHARMACIST_ROLE(), msg.sender),
            "Only pharmacist allowed"
        );
        _;
    }
    modifier onlyRegulator() {
        require(
            accessControl.hasRole(accessControl.REGULATOR_ROLE(), msg.sender),
            "Only regulator allowed"
        );
        _;
    }
    modifier batchExists(string memory batchId) {
        require(drugBatches[batchId].manufacturer != address(0), "Batch not found");
        _;
    }
    modifier notFlagged(string memory batchId) {
        require(!drugBatches[batchId].isFlagged, "Batch is flagged as counterfeit");
        _;
    }

    // ─────────────────────────────────────────────────────────────
    // Constructor
    // ─────────────────────────────────────────────────────────────
    constructor(address _accessControl, address _prescriptionContract) {
        require(_accessControl         != address(0), "Invalid access control");
        require(_prescriptionContract  != address(0), "Invalid prescription contract");
        accessControl         = IAccessControl(_accessControl);
        prescriptionContract  = IPrescriptionAndDiagnosis(_prescriptionContract);
    }

    // ─────────────────────────────────────────────────────────────
    // Manufacturer functions
    // ─────────────────────────────────────────────────────────────

    /**
     * @notice Register a new drug batch on-chain.
     *         Only callable by wallets with MANUFACTURER_ROLE.
     */
    function registerDrug(
        string memory batchId,
        string memory drugName
    )
        external
        onlyManufacturer
        nonReentrant
    {
        require(bytes(batchId).length  > 0, "Batch ID required");
        require(bytes(drugName).length > 0, "Drug name required");
        require(drugBatches[batchId].manufacturer == address(0), "Batch already registered");

        drugBatches[batchId] = DrugBatch({
            batchId:        batchId,
            drugName:       drugName,
            manufacturer:   msg.sender,
            currentOwner:   msg.sender,
            status:         DrugStatus.Manufactured,
            isFlagged:      false,
            registeredAt:   block.timestamp,
            updatedAt:      block.timestamp
        });

        _addStageEntry(batchId, DrugStatus.Manufactured, msg.sender, "Registered by manufacturer");
        emit DrugRegistered(batchId, drugName, msg.sender, block.timestamp);
    }

    /**
     * @notice Transfer batch to a distributor.
     *         Only the current owner (manufacturer) can call this.
     *         Recipient must hold DISTRIBUTOR_ROLE.
     */
    function transferToDistributor(string memory batchId, address distributor)
        external
        batchExists(batchId)
        notFlagged(batchId)
        nonReentrant
    {
        DrugBatch storage b = drugBatches[batchId];
        require(b.currentOwner == msg.sender,                    "Not the current owner");
        require(b.status == DrugStatus.Manufactured,             "Can only transfer from Manufactured state");
        require(distributor != address(0),                       "Invalid distributor address");
        require(
            accessControl.hasRole(accessControl.DISTRIBUTOR_ROLE(), distributor),
            "Recipient does not have DISTRIBUTOR role"
        );

        b.currentOwner = distributor;
        b.status       = DrugStatus.InTransit;
        b.updatedAt    = block.timestamp;

        _addStageEntry(batchId, DrugStatus.InTransit, msg.sender, "Transferred to distributor");
        emit DrugTransferredToDistributor(batchId, msg.sender, distributor, block.timestamp);
    }

    // ─────────────────────────────────────────────────────────────
    // Pharmacy functions
    // ─────────────────────────────────────────────────────────────

    /**
     * @notice Pharmacy confirms receipt of the batch.
     *         Only callable by wallets with PHARMACIST_ROLE.
     *         Batch must be InTransit and pharmacy must be the current owner.
     */
    function receiveAtPharmacy(string memory batchId)
        external
        onlyPharmacist
        batchExists(batchId)
        notFlagged(batchId)
        nonReentrant
    {
        DrugBatch storage b = drugBatches[batchId];
        require(b.currentOwner == msg.sender,        "Not the current owner");
        require(b.status == DrugStatus.InTransit,    "Batch is not InTransit");

        b.status    = DrugStatus.AtPharmacy;
        b.updatedAt = block.timestamp;

        _addStageEntry(batchId, DrugStatus.AtPharmacy, msg.sender, "Received at pharmacy");
        emit DrugReceivedAtPharmacy(batchId, msg.sender, block.timestamp);
    }

    /**
     * @notice Sell the drug to a patient.
     *         Requires a valid, unexpired prescription.
     *         Calls PrescriptionAndDiagnosis.dispensePrescription() to close the loop.
     * @param  batchId          The drug batch being sold
     * @param  prescriptionId   ID of the patient's prescription from PrescriptionAndDiagnosis
     */
    function markAsSold(string memory batchId, uint256 prescriptionId)
        external
        onlyPharmacist
        batchExists(batchId)
        notFlagged(batchId)
        nonReentrant
    {
        DrugBatch storage b = drugBatches[batchId];
        require(b.currentOwner == msg.sender,      "Not the current owner");
        require(b.status == DrugStatus.AtPharmacy, "Batch must be AtPharmacy before sale");

        // ── Cross-contract prescription validation ────────────────
        require(
            prescriptionContract.isValidPrescription(prescriptionId),
            "No valid, unexpired prescription found"
        );

        // ── Update state BEFORE external call (CEI pattern) ───────
        b.status    = DrugStatus.Sold;
        b.updatedAt = block.timestamp;

        _addStageEntry(batchId, DrugStatus.Sold, msg.sender, "Sold to patient");
        emit DrugSold(batchId, msg.sender, prescriptionId, block.timestamp);

        // ── Mark prescription as dispensed ────────────────────────
        prescriptionContract.dispensePrescription(prescriptionId);
    }

    // ─────────────────────────────────────────────────────────────
    // Counterfeit flagging — anyone can flag, regulator can unflag
    // ─────────────────────────────────────────────────────────────

    /**
     * @notice Flag a batch as potentially counterfeit.
     *         Any registered user can flag — regulators investigate.
     */
    function flagCounterfeit(string memory batchId, string memory reason)
        external
        batchExists(batchId)
    {
        require(bytes(reason).length > 0, "Reason required");
        drugBatches[batchId].isFlagged  = true;
        drugBatches[batchId].status     = DrugStatus.Flagged;
        drugBatches[batchId].updatedAt  = block.timestamp;

        _addStageEntry(batchId, DrugStatus.Flagged, msg.sender, reason);
        emit CounterfeitFlagged(batchId, msg.sender, reason, block.timestamp);
    }

    /**
     * @notice Regulator clears a false-positive counterfeit flag.
     */
    function clearFlag(string memory batchId, DrugStatus previousStatus)
        external
        onlyRegulator
        batchExists(batchId)
        nonReentrant
    {
        require(drugBatches[batchId].isFlagged, "Batch is not flagged");
        drugBatches[batchId].isFlagged = false;
        drugBatches[batchId].status    = previousStatus;
        drugBatches[batchId].updatedAt = block.timestamp;

        _addStageEntry(batchId, previousStatus, msg.sender, "Flag cleared by regulator");
    }

    // ─────────────────────────────────────────────────────────────
    // View functions
    // ─────────────────────────────────────────────────────────────

    /**
     * @notice Public drug verification — anyone can call this.
     *         Used by the QR code scanner on the website.
     */
    function verifyDrug(string memory batchId)
        external
        view
        returns (
            string  memory drugName,
            address manufacturer,
            address currentOwner,
            DrugStatus status,
            bool    isFlagged,
            uint256 updatedAt
        )
    {
        DrugBatch memory d = drugBatches[batchId];
        require(d.manufacturer != address(0), "Drug batch not found");
        return (d.drugName, d.manufacturer, d.currentOwner, d.status, d.isFlagged, d.updatedAt);
    }

    /**
     * @notice Returns the full stage history for a batch.
     *         Powers the supply chain timeline UI on the website.
     */
    function getStageHistory(string memory batchId)
        external
        view
        batchExists(batchId)
        returns (StageEntry[] memory)
    {
        return _stageHistory[batchId];
    }

    // ─────────────────────────────────────────────────────────────
    // Internal helpers
    // ─────────────────────────────────────────────────────────────
    function _addStageEntry(
        string memory batchId,
        DrugStatus    stage,
        address       actor,
        string memory note
    ) internal {
        _stageHistory[batchId].push(StageEntry({
            stage:     stage,
            actor:     actor,
            timestamp: block.timestamp,
            note:      note
        }));
    }
}
